/*
@접근
    10^5이므로 O(n^2)보다 낮아야할듯
     ㄴ n^2/4 같은게 아니면 O(n^2)는 무조건 TLE이 발생할 것
    해시로 각 합이 몇번씩 나왔는지 카운트하고 제일 적게 카운트된 것을 쓰면 되지 않을까?
     ㄴ limit때문에 이게 안 되는 경우가 있음
     ㄴ limit이 4이고 (3,4), (2,2)인 경우, (2,2)을 7로 맞추기 위해선 2개 전부 바꿔야함
     ㄴ 하지만 (3,4)를 4로 맞추려면 1개만 바꾸면 됨
    각 쌍은 1개만 바꿔서 도달할 수 있는 범위가 있음
     ㄴ (a,b)이고, a<=b인 경우, 1+a ~ b+limit가 1개만 바꿔서 도달 가능한 범위
    이 이산 분포를 전부 합치는 방식은 어떨까?
     ㄴ 2*(l+n) -> 4 * 10^5가 나옴
     ㄴ 그런데 이산 분포의 합은 2*l 길이 벡터를 마련해야되기에 꽤 무거움
     ㄴ 실행 결과, TLE 발생
    수직선 상에 어떤 구간들이 있고, 최대한 많은 구간들에 포함되는 한 점을 찾기...
     ㄴ 숫자쌍 (a,a+r)과 같이 표현할 수 있고, a+1 ~ a+r+l로 생각하자...
     ㄴ 이를 이용해 구간의 시작점과 너비로 데이터를 표현할 수 있게 됨
     ㄴ 그런데 뒤의 과정을 생각해보면 너비가 아니라 종점을 저장하는게 더 좋은듯?
    구간들을 시작점 오름차순, 같을 시 너비 오름차순으로 정렬하면, 구간을 순서대로 고를 수 있게 됨
     ㄴ 앞에서 선택한 구간을 뒤의 구간을 담기 위해 버리는 것이 유효해짐
     ㄴ 제일 앞의 구간 끝과 제일 뒤의 구간의 시작점을 비교...
    그리고 몇개를 담았는지를 DP처럼 기록하고, 나중에 이를 통해 정답을 구성
     ㄴ 최대 개수와 그 구간의 complementary 지점이 얼마나 겹치는지 알기만 하면 됨
     ㄴ 전체 개수*2 - 최대 개수 - comple지점 개수
    시간 복잡도 예상 O(nlogn)
     ㄴ n + nlogn + n/2 + n/2
   
@실패
    선택한 comple 포인트가 구간들 중 바깥에 존재하는 경우가 존재함
     ㄴ 구간들의 집합이지만, 그 구간들끼리 완전히 겹쳐지는 것은 아님
     ㄴ 때문에 comple 포인트에 닿기 위해 양쪽 숫자 모두 바꿔야 하는 케이스가 존재함
     ㄴ 즉, 단순히 경계값만으로 해결할 수 있는 문제는 아님
    이를 해결하기 위해선 필연적으로 comple 포인트별로 구간들에 대한 평가이 필요함
     ㄴ 최악의 경우, 구간 전체가 남고 구간별로 서로 다른 comple 포인트를 가질 수 있음
     ㄴ 이렇게 되면 O(n^2)가 되기 때문에 TLE이 발생할 수밖에 없음
    따라서 현재 접근법으로는 해당 문제를 풀 수 없음
    1개만 바꾸면 되는 경우는 충분히 해결 가능한 것으로 보이지만,
    이 문제처럼 구간 내에 한 지점에서 0개가 되는 경우는 해결할 수 없음
     ㄴ 수치해석으로 비유하자면 step 사이에 추세와 크게 다른 점이 있는 것과 같음
    하지만 구간의 overlap 아이디어나 그 해결법은 가져갈만 하다고 생각됨
*/

class Solution {
public:
    int minMoves(vector<int>& nums, int limit) {
        const int numsSize = nums.size();
        vector<vector<int>> segment(numsSize/2,vector<int>(2));
        vector<int> counter(numsSize/2,0);

        for (int i = 0; i < numsSize/2; ++i)
        {
            segment[i] = {
                min(nums[i],nums[numsSize-i-1])+1,
                max(nums[i],nums[numsSize-i-1])+limit
            };
        }
        sort(segment.begin(), segment.end(), [](const vector<int>& lhs, const vector<int>& rhs){
             return (lhs[0] == rhs[0]) ? (lhs[1] < rhs[1]) : (lhs[0] < rhs[0]);
            });

        int ptr = 0;
        int maxCountIdx = 0;
        counter[0] = 0;

        for(int i = 0; i < numsSize/2; ++i)
        {
            while (ptr < numsSize/2 && segment[ptr][1] < segment[i][0])
            {
                ptr++;
            }

            counter[i] = i-ptr+1;
            if (counter[maxCountIdx] < i-ptr+1)
                maxCountIdx = i;
        }

        int maxSameComple = -10e5;
        int beginIdx = maxCountIdx-counter[maxCountIdx]+1;
        int lowBnd = segment[beginIdx][0];
        int highBnd = segment[beginIdx][1];
        unordered_map<int,int> complCount;

        for(int i = beginIdx; i <= maxCountIdx; ++i)
        {
            int comple = segment[i][0]+segment[i][1]-limit-1;

            if (complCount.find(comple) == complCount.end())
            {
                int outOfBound = 0;

                for (int j = beginIdx; j <= maxCountIdx; ++j)
                {
                    if (comple < segment[j][0])
                        outOfBound++;
                    else if (segment[j][1] < comple)
                        outOfBound++;
                }

                complCount[comple] = 1 - outOfBound;
            }
            else
            {
                complCount[comple]++;
                maxSameComple = max(maxSameComple,complCount[comple]);
            }
        }

        cout << lowBnd << " ~ " << highBnd << endl;

        for (auto it = complCount.begin(); it != complCount.end(); ++it)
        {
            if (it->second > 1)
                cout << it->first << " : " << it->second << endl;
        }
        cout << numsSize << " " << counter[maxCountIdx] << " " << maxSameComple << endl;

        return numsSize - counter[maxCountIdx] - maxSameComple;
    }
};

